import{_ as e,o,c as r,ag as a}from"./chunks/framework.CO1DiHOz.js";const p=JSON.parse('{"title":"What is ra?","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/index.md","filePath":"concepts/index.md"}'),n={name:"concepts/index.md"};function s(i,t,d,l,c,h){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="what-is-ra" tabindex="-1">What is ra? <a class="header-anchor" href="#what-is-ra" aria-label="Permalink to &quot;What is ra?&quot;">​</a></h1><blockquote><p><strong>ra</strong> is a <strong>r</strong>aw <strong>a</strong>gent. A <strong>r</strong>ole <strong>a</strong>gent. A <strong>r</strong>un-<strong>a</strong>nything <strong>a</strong>gent.</p><p>One binary you configure into whatever agent you need — without rewriting anything.</p></blockquote><p>Same binary. Different config. Different agent.</p><ul><li>Drop a <code>ra.config.yml</code> in a repo → a project-specific assistant with its own system prompt, skills, and tools</li><li>Set env vars → a different provider, a different persona, the same CLI</li><li>Pass <code>--skill</code> → inject a role or behavior at runtime</li><li>Run <code>--mcp</code> → expose it as a tool to Cursor, Claude Desktop, or anything MCP-aware</li></ul><h2 id="why-ra" tabindex="-1">Why ra? <a class="header-anchor" href="#why-ra" aria-label="Permalink to &quot;Why ra?&quot;">​</a></h2><p>Most AI tools lock you into one shape — a chat UI, a framework, a cloud product. ra is the opposite. It&#39;s an <strong>agent primitive</strong>: small, composable, and configurable enough to become whatever you need.</p><p>Give it a system prompt and it has a personality. Give it skills and it has expertise. Connect MCP servers and it has tools. Point it at a different provider and it speaks a different model. The binary never changes — only the configuration does.</p><p>That&#39;s what makes ra powerful for <strong>agentic loops</strong>. Drop a config file alongside your code, run <code>ra &quot;do the thing&quot;</code>, and you have a domain-specific agent that understands your codebase, your tools, and your workflow. Need a code reviewer? A support bot? A CI agent? Same binary, different <code>ra.config.yml</code>.</p><h2 id="what-s-in-the-box" tabindex="-1">What&#39;s in the box <a class="header-anchor" href="#what-s-in-the-box" aria-label="Permalink to &quot;What&#39;s in the box&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>REPL</strong></td><td>Interactive sessions with history</td></tr><tr><td><strong>One-shot CLI</strong></td><td>Scriptable prompts, streams to stdout</td></tr><tr><td><strong>HTTP API</strong></td><td>Sync + streaming chat, session management</td></tr><tr><td><strong>MCP client</strong></td><td>Pull tools from other MCP servers</td></tr><tr><td><strong>MCP server</strong></td><td>Expose ra as a tool to other apps</td></tr><tr><td><strong>Tool calling</strong></td><td>Model invokes functions, ra executes them</td></tr><tr><td><strong>Skills</strong></td><td>Reusable instruction bundles — roles, behaviors, and assets</td></tr><tr><td><strong>File attachments</strong></td><td>Attach files in CLI and REPL</td></tr><tr><td><strong>Session storage</strong></td><td>Persist conversations, resume later, auto-prune old ones</td></tr><tr><td><strong>Layered config</strong></td><td>File → env → CLI override order; commit a baseline, tweak per-run</td></tr></tbody></table>',10)])])}const u=e(n,[["render",s]]);export{p as __pageData,u as default};
